package evaluation

import "fmt"

// EvaluationError represents an error that occurred during flag evaluation,
// wrapping the underlying cause with evaluation context (namespace, flag, phase).
type EvaluationError struct {
	namespaceKey string
	flagKey      string
	phase        string
	cause        error
}

// Error implements the error interface with a descriptive message including evaluation context.
func (e *EvaluationError) Error() string {
	return fmt.Sprintf("evaluation error for namespace %q flag %q during %s: %s", e.namespaceKey, e.flagKey, e.phase, e.cause.Error())
}

// Unwrap returns the underlying cause for use with errors.As/errors.Is.
func (e *EvaluationError) Unwrap() error {
	return e.cause
}

// newEvaluationError wraps err with evaluation context identifying the namespace, flag, and phase.
func newEvaluationError(namespaceKey, flagKey, phase string, cause error) error {
	return &EvaluationError{
		namespaceKey: namespaceKey,
		flagKey:      flagKey,
		phase:        phase,
		cause:        cause,
	}
}

